f["312"] = {"steps":["Enter the deposit amount","Enter the annual interest rate","Enter the term in months or years","For simple interest: interest = deposit x rate x years","For compound: maturity = deposit x (1 + rate/n)^(n x years)","The maturity value is what you receive at the end of the term"],"mistakes":["Not checking whether interest is simple or compound — the difference can be substantial","Withdrawing before maturity — penalties can wipe out interest earned","Not comparing fixed deposit rates across banks — they vary significantly"],"result_context":"A fixed deposit of {deposito} at {tasa}% for {plazo} will mature at {monto_final}.","formula_display":"Maturity = deposit x (1 + rate x years) for simple; = deposit x (1 + rate/n)^(nt) for compound","example_label":"Maturity value of a 5,000 fixed deposit at 3.5% for 2 years"}
f["326"] = {"steps":["Enter the total debt balance","Enter the annual interest rate (APR)","Enter your monthly payment amount","Calculate months to payoff: complex iterative formula","Total interest paid over the payoff period","Payoff date is today plus the calculated months"],"mistakes":["Making only minimum payments — it takes years longer and costs thousands more in interest","Not accounting for annual fees and late payment charges","Continuing to use the card while trying to pay it off"],"result_context":"With monthly payments of {pago}, you will pay off {deuda} at {tasa}% in {meses} months, paying {interes_total} in interest.","formula_display":"Months = log(payment / (payment - debt x r/12)) / log(1 + r/12)","example_label":"Payoff time for 5,000 credit card debt at 18% APR with 200 monthly payments"}
f["327"] = {"steps":["Enter the credit card balance","Enter the APR (annual percentage rate)","Enter your fixed monthly payment","Calculate: months to payoff using the debt formula","Total interest = (monthly payment x months) minus balance","To pay off faster, increase the monthly payment or transfer to a lower-rate card"],"mistakes":["Paying only the minimum — it can take 10+ years to clear a modest balance","Missing a payment — late fees and penalty APRs make the debt grow faster","Not considering balance transfer fees when moving debt to a 0% card"],"result_context":"Paying {pago} per month on a {saldo} balance at {tasa}% APR will take {meses} months to clear.","formula_display":"Months = -log(1 - balance x r/12 / payment) / log(1 + r/12)","example_label":"Payoff time for 3,000 at 22% APR with 150 monthly payments"}
