f["400"] = {"steps":["Enter your weight in kilograms","Enter your height in meters","Calculate: BMI = weight / (height x height)","Compare result to categories: under 18.5 = underweight, 18.5-25 = normal, 25-30 = overweight, over 30 = obese","BMI is a screening tool, not a diagnosis"],"mistakes":["Using pounds and inches without converting to metric","Treating BMI as a definitive measure of health — it does not account for muscle mass","Applying adult BMI categories to children — pediatric BMI uses percentile charts"],"result_context":"With a weight of {peso} kg and height of {altura} m, your BMI is {bmi}, which falls in the {categoria} range.","formula_display":"BMI = weight (kg) / height (m)²","example_label":"Calculate BMI for a person weighing 70 kg at 1.75 m tall"}
f["403"] = {"steps":["Enter your body weight in kg","Enter your activity level (sedentary to very active)","Base recommendation: 30-35 ml per kg of body weight","Add extra for exercise: 350-700 ml per hour of moderate activity","Add extra for hot climates: 500-1000 ml additional","Total daily water intake = base + exercise + climate adjustment"],"mistakes":["Drinking too much water too quickly — the kidneys can only process about 800-1000 ml per hour","Counting coffee and soda as water — caffeine is a diuretic","Ignoring water content in food — fruits and vegetables contribute significantly"],"result_context":"Based on your weight of {peso} kg, you should drink approximately {agua_diaria} liters of water per day.","formula_display":"Water (L) = weight (kg) x 0.033 + exercise adjustment","example_label":"Daily water intake for a 70 kg person with moderate activity"}
f["405"] = {"steps":["Enter your weight, height, age, and select gender","The Harris-Benedict formula calculates BMR differently for men and women","Men: BMR = 88.362 + (13.397 x weight) + (4.799 x height) - (5.677 x age)","Women: BMR = 447.593 + (9.247 x weight) + (3.098 x height) - (4.330 x age)","BMR is the calories your body burns at complete rest","TDEE = BMR x activity factor (1.2 to 1.9)"],"mistakes":["Using BMR as your total calorie needs — it is only your resting metabolism","Not updating BMR as weight changes — even 5 kg changes BMR noticeably","Applying the formula to athletes or very muscular people — it underestimates their needs"],"result_context":"Your Basal Metabolic Rate is approximately {bmr} calories per day at complete rest.","formula_display":"BMR (male) = 88.362 + 13.397W + 4.799H - 5.677A; BMR (female) = 447.593 + 9.247W + 3.098H - 4.330A","example_label":"BMR for a 30 year old male, 80 kg, 180 cm"}
f["419"] = {"steps":["Enter your pre-pregnancy weight and height to calculate BMI","Recommended total weight gain depends on pre-pregnancy BMI","Underweight (BMI <18.5): gain 12.5-18 kg","Normal weight (BMI 18.5-25): gain 11.5-16 kg","Overweight (BMI 25-30): gain 7-11.5 kg","Obese (BMI >30): gain 5-9 kg"],"mistakes":["Trying to lose weight during pregnancy — can harm the baby","Comparing weight gain to non-pregnant friends — pregnancy weight gain is mostly baby, placenta, fluids, and blood volume","Not accounting for carrying twins or multiples — weight gain recommendations are higher"],"result_context":"Based on your pre-pregnancy BMI of {imc}, the recommended total weight gain is {ganancia_min} to {ganancia_max} kg.","formula_display":"Gain range based on pre-pregnancy BMI category","example_label":"Recommended weight gain for someone starting at BMI 22"}
f["422"] = {"steps":["Enter your age in years","The simplest formula: max heart rate = 220 minus age","Alternative Tanaka formula: MHR = 208 - (0.7 x age) for better accuracy","Your training zones are percentages of your MHR","Fat burn zone: 60-70% of MHR; Cardio: 70-80%; Peak: 80-95%"],"mistakes":["Using 220 minus age for everyone — it can be off by 10-15 beats for many people","Training at maximum heart rate — it is called maximum for a reason, do not sustain it","Forgetting that certain medications (beta blockers) lower maximum heart rate"],"result_context":"Your estimated maximum heart rate is {fcm} bpm. Your fat-burning zone is {zona_quema} bpm.","formula_display":"MHR = 220 - age (standard) or MHR = 208 - 0.7 x age (Tanaka)","example_label":"Max heart rate and training zones for a 35 year old"}
f["423"] = {"steps":["Enter your maximum heart rate or calculate it from age","Zone 1 (Recovery): 50-60% of MHR — very light activity","Zone 2 (Fat burn): 60-70% — best for endurance and fat metabolism","Zone 3 (Cardio): 70-80% — improves aerobic capacity","Zone 4 (Threshold): 80-90% — improves lactate threshold","Zone 5 (Maximum): 90-100% — sprint and peak performance"],"mistakes":["Spending all training time in zone 3 — zone 2 builds the aerobic base needed for progress","Not using a heart rate monitor — perceived effort is often inaccurate","Training at high intensity every day — the body needs recovery in zones 1 and 2"],"result_context":"Your five training zones range from {z1} to {z5} bpm based on your maximum heart rate of {fcm}.","formula_display":"Zone N = MHR x (lower% to upper%)","example_label":"Heart rate training zones for someone with MHR of 185 bpm"}
f["424"] = {"steps":["Measure your true resting heart rate first thing in the morning","Enter your resting heart rate and maximum heart rate","Heart rate reserve (HRR) = MHR minus resting HR","Karvonen target = (HRR x intensity%) + resting HR","This formula accounts for your fitness level, unlike simple % of MHR"],"mistakes":["Using an estimated resting heart rate — measure it for accuracy","Applying the same zones as simple MHR percentages — Karvonen zones are different","Not re-measuring resting HR as fitness improves — it drops with better conditioning"],"result_context":"Using the Karvonen method with resting HR of {fc_reposo}, your target heart rate at {intensidad}% is {fc_objetivo} bpm.","formula_display":"Target HR = ((MHR - resting HR) x intensity%) + resting HR","example_label":"Karvonen target at 70% intensity with resting HR 60 and MHR 185"}
f["429"] = {"steps":["Enter your body weight","Select the exercise type from the list","Enter the duration in minutes","Calories burned = MET value x weight (kg) x duration (hours)","MET values: walking 3.5, jogging 7, cycling 8, swimming 6, weight training 5","The heavier you are, the more calories you burn for the same exercise"],"mistakes":["Overestimating intensity — casual cycling is not the same as vigorous cycling","Not accounting for rest periods during exercise","Using exercise calories as an excuse to overeat — weight loss comes from diet, not exercise"],"result_context":"{duracion} minutes of {actividad} burns approximately {calorias} calories for someone weighing {peso} kg.","formula_display":"Calories = MET x weight (kg) x hours","example_label":"Calories burned in 30 minutes of jogging at 70 kg"}
f["439"] = {"steps":["Enter your systolic (top) reading and diastolic (bottom) reading","Normal: systolic <120 AND diastolic <80 mmHg","Elevated: systolic 120-129 AND diastolic <80","Stage 1 hypertension: systolic 130-139 OR diastolic 80-89","Stage 2 hypertension: systolic >=140 OR diastolic >=90","Hypertensive crisis: systolic >180 OR diastolic >120 — seek medical help"],"mistakes":["Taking a single reading and panicking — blood pressure varies throughout the day","Using a cuff that is the wrong size — too small overestimates, too large underestimates","Measuring right after exercise, coffee, or stress — rest for 5 minutes first"],"result_context":"A reading of {sistolica}/{diastolica} mmHg is classified as {categoria}. Your mean arterial pressure is {map} mmHg.","formula_display":"MAP = diastolic + (systolic - diastolic) / 3","example_label":"Classify a blood pressure reading of 135/85 mmHg"}
f["443"] = {"steps":["Sleep cycles last approximately 90 minutes each","Waking up mid-cycle leaves you groggy","To wake at 7:00 AM, go to bed at 9:45 PM (6 cycles), 11:15 PM (5 cycles), or 12:45 AM (4 cycles)","The average person needs 5-6 full sleep cycles (7.5-9 hours)","Sleep onset takes about 15 minutes — add this to your bedtime calculation"],"mistakes":["Hitting snooze repeatedly — you start a new sleep cycle you will not finish","Using screens right before bed — blue light suppresses melatonin for 1-2 hours","Drinking alcohol before bed — it fragments sleep cycles even if you fall asleep faster"],"result_context":"For {ciclos} complete sleep cycles, plan to sleep for {horas} hours. Suggested bedtimes: {horarios}.","formula_display":"Sleep time = number of cycles x 90 minutes; Wake time = bedtime + sleep time + 15 min onset","example_label":"Best bedtime to wake up at 6:30 AM feeling refreshed"}

# ── SCIENCE ──
f["503"] = {"steps":["Enter the mass in kilograms","Enter the acceleration in m/s²","Apply Newton's Second Law: F = m x a","The result is in Newtons (N)","1 N is the force needed to accelerate 1 kg at 1 m/s²","Multiple forces add as vectors, not simple numbers"],"mistakes":["Using weight (in kg-force) instead of mass (in kg) — they are different concepts","Confusing Newtons with kilograms — weight is mass x gravity, force is mass x acceleration","Adding forces without considering direction — forces are vector quantities"],"result_context":"A mass of {masa} kg accelerating at {aceleracion} m/s² experiences a force of {fuerza} N.","formula_display":"F = m x a (Newton's Second Law)","example_label":"Force needed to accelerate a 1,200 kg car at 3 m/s²"}
f["504"] = {"steps":["Enter the mass of the object in kg","Enter the velocity in m/s","Kinetic energy = 0.5 x mass x velocity²","The result is in Joules (J)","Kinetic energy increases with the square of velocity — doubling speed quadruples energy","This is why high-speed collisions are so much more destructive"],"mistakes":["Using km/h instead of m/s — divide km/h by 3.6 to convert","Forgetting to square the velocity before multiplying","Confusing kinetic energy with momentum — they scale differently with velocity"],"result_context":"An object with mass {masa} kg moving at {velocidad} m/s has a kinetic energy of {energia} J.","formula_display":"KE = ½mv²","example_label":"Kinetic energy of a 1,500 kg car traveling at 20 m/s (72 km/h)"}
f["514"] = {"steps":["Enter the initial velocity in m/s","Enter the launch angle in degrees (from horizontal)","Maximum height = (v² x sin²(angle)) / (2 x g)","Range = (v² x sin(2 x angle)) / g","Flight time = (2 x v x sin(angle)) / g","g = 9.81 m/s² (standard gravity)","Optimal angle for maximum range is 45 degrees"],"mistakes":["Using degrees instead of radians in the sine function","Forgetting air resistance — real projectiles travel shorter than calculated","Assuming flat ground — launching from or to different elevations changes the trajectory"],"result_context":"A projectile launched at {vi} m/s at {angulo} degrees reaches {altura_max} m high and lands {alcance} m away after {tiempo_vuelo} seconds.","formula_display":"Range = v²sin(2θ)/g; Height = v²sin²(θ)/(2g); Time = 2vsin(θ)/g","example_label":"Trajectory of a ball thrown at 25 m/s at a 40 degree angle"}

