f["601"] = {"steps":["Enter the start date (day, month, year)","Enter the end date (day, month, year)","The calculator counts the total days between the two dates","Use this for project duration, age calculation, countdown to events","Result can be shown in days, weeks, or months","Accounting for leap years is automatic"],"mistakes":["Counting the start date as day 1 when it should be day 0","Forgetting that months have different numbers of days","Not accounting for time zones when calculating across international date lines"],"result_context":"There are {dias} days between {fecha_inicio} and {fecha_fin}.","formula_display":"Days = end date - start date","example_label":"Days between January 15 and March 10 of the same year"}
f["604"] = {"steps":["Enter the start date and end date","The calculator identifies all weekdays (Mon-Fri)","Subtracts weekends automatically","Optionally add holiday dates to exclude","Result is the number of business/working days","Use for project planning, payroll, and delivery estimates"],"mistakes":["Not checking for regional public holidays — they vary by country and region","Assuming all weekdays are working days — some countries have different work weeks","Forgetting that some businesses close between Christmas and New Year"],"result_context":"There are {dias_habiles} working days between {fecha_inicio} and {fecha_fin}, excluding weekends.","formula_display":"Working days = total days - weekend days - holidays","example_label":"Working days in January 2026"}
f["610"] = {"steps":["Enter the password to test","Password strength depends on length and character variety","Entropy in bits = length x log2(possible characters)","Lowercase only = 26 chars, +uppercase = 52, +digits = 62, +symbols = 95","Under 40 bits = weak, 40-60 = moderate, 60-80 = strong, 80+ = very strong","Crack time estimate based on 10 billion guesses per second"],"mistakes":["Using dictionary words — attackers try these first with variations","Thinking adding '1!' at the end makes a password strong — pattern-based attacks check these","Reusing passwords across sites — one breach exposes all accounts"],"result_context":"Your password has approximately {entropia} bits of entropy. Estimated crack time: {tiempo_crack}.","formula_display":"Entropy = length x log2(charset size); Crack time = 2^(entropy-1) / guesses per second","example_label":"Test password strength of 'Tr0ub4dor&3'"}
f["611"] = {"steps":["Select the desired password length (12-16 recommended)","Choose character types: lowercase, uppercase, digits, symbols","The generator creates a random password from the selected set","Each character is independently random — no patterns or words","Copy the password to a password manager immediately"],"mistakes":["Writing passwords on paper or in unencrypted files","Generating a password and then memorizing it — use a password manager instead","Choosing too short — 8 characters can be cracked in minutes, 16 takes years"],"result_context":"Your randomly generated password is {contrasena}. Store it securely in a password manager.","formula_display":"Random selection from charset of size N for L positions = N^L combinations","example_label":"Generate a 16-character password with all character types"}
f["614"] = {"steps":["Enter the file size and select the current unit (bytes, KB, MB, etc.)","The calculator converts between all digital storage units","1 KB = 1024 bytes, 1 MB = 1024 KB, 1 GB = 1024 MB, 1 TB = 1024 GB","Note: hard drive manufacturers often use 1000 instead of 1024","Result shows the file size in all common units"],"mistakes":["Confusing MB (megabytes) with Mb (megabits) — 1 MB = 8 Mb","Using 1000-based conversion when your OS uses 1024-based","Not accounting for file system overhead — files take slightly more space on disk"],"result_context":"{tamano} converts to {resultado}.","formula_display":"Divide by 1024 for each step up: B -> KB -> MB -> GB -> TB","example_label":"Convert 500 MB to GB, KB, and bytes"}
f["628"] = {"steps":["Enter the distance traveled in km or miles","Enter the amount of fuel used in liters or gallons","Calculate: consumption = fuel used / distance x 100 (L/100km)","Alternative: fuel economy = distance / fuel used (MPG or km/L)","Lower L/100km means better efficiency","Typical car: 6-8 L/100km; SUV: 9-12 L/100km"],"mistakes":["Calculating from a single trip — fill the tank, record distance, fill again for accuracy","Comparing L/100km with MPG without converting — they are inversely related","Not accounting for different driving conditions — city vs highway consumption differs significantly"],"result_context":"Your vehicle consumes {consumo} L per 100 km, which equals {rendimiento} km per liter.","formula_display":"Consumption (L/100km) = fuel used / distance x 100","example_label":"Fuel consumption over 450 km using 36 liters"}

# ── ELECTRONICS ──
f["900"] = {"steps":["Ohm's Law: V = I x R (voltage = current x resistance)","Enter any two known values to find the third","To find voltage: V = I x R","To find current: I = V / R","To find resistance: R = V / I","Units: volts (V), amps (A), ohms (Ω)"],"mistakes":["Using the wrong units — milliamps must be converted to amps first","Applying Ohm's law to non-linear components like diodes and transistors","Forgetting that real wires have resistance too — especially in long runs"],"result_context":"With {voltaje} V and {corriente} A, the resistance is {resistencia} Ω.","formula_display":"V = I x R; I = V / R; R = V / I","example_label":"Find the current through a 220 Ω resistor with 5 V applied"}
f["902"] = {"steps":["Enter the supply voltage (from your power source)","Enter the forward voltage of the LED (typically 2 V for red, 3.2 V for blue/white)","Enter the desired LED current (typically 20 mA = 0.02 A)","Calculate: resistor = (supply V - LED V) / current","Round up to the nearest standard resistor value","Higher resistance = dimmer LED; lower resistance = brighter but may burn out"],"mistakes":["Connecting the LED without a current-limiting resistor — it will burn out instantly","Using the supply voltage alone in the calculation — subtract the LED forward voltage","Forgetting that different LED colors have different forward voltages"],"result_context":"For a {voltaje_fuente} V supply with a {voltaje_led} V LED at {corriente} mA, use a {resistencia} Ω resistor.","formula_display":"R = (Vsupply - Vled) / Iled","example_label":"Resistor for a red LED (2V, 20mA) on a 9V battery"}
f["903"] = {"steps":["Identify the colored bands on the resistor (4, 5, or 6 bands)","First band = first digit, second band = second digit","Third band = multiplier (number of zeros)","Fourth band = tolerance (gold = 5%, silver = 10%, none = 20%)","5-band resistors have three significant digits","6-band adds a temperature coefficient"],"mistakes":["Reading the bands in the wrong direction — the tolerance band has a wider gap","Confusing brown (1) with red (2) or orange (3) in poor lighting","Assuming a 4-band resistor when it is actually 5-band"],"result_context":"The resistor color code decodes to {resistencia} Ω with {tolerancia}% tolerance.","formula_display":"Value = (digit1 digit2) x 10^multiplier Ω","example_label":"Decode a 4-band resistor: brown, black, red, gold"}
f["906"] = {"steps":["Enter the input voltage (Vin)","Enter the values of R1 (top resistor) and R2 (bottom resistor)","Output voltage: Vout = Vin x R2 / (R1 + R2)","The divider splits voltage in proportion to the resistor values","If R1 = R2, Vout = Vin / 2","Used for level shifting, reference voltages, and sensor circuits"],"mistakes":["Not accounting for the load connected to Vout — it changes the effective R2","Using very high resistor values — noise becomes significant above 1 MΩ","Using very low values — wastes power through the divider"],"result_context":"With {vin} V input and R1={r1}Ω, R2={r2}Ω, the output voltage is {vout} V.","formula_display":"Vout = Vin x R2 / (R1 + R2)","example_label":"Output of a divider with 12V in, R1=10kΩ, R2=5kΩ"}

